const now = new Date();
const day = now.getDay();
const dayMap = { 1: 'monday', 3: 'wednesday', 5: 'friday' };
const dayLabel = dayMap[day] || 'monday';
const sevenDaysAgo = new Date(now - 7 * 24 * 60 * 60 * 1000).toISOString();
return [{ json: { dayLabel, runAt: now.toISOString(), sevenDaysAgo } }];

const subscribers = $('Supabase — Fetch All Subscribers').first().json;
const sevenDaysAgo = new Date($('Code — Get Day').first().json.sevenDaysAgo);
const dayLabel = $('Code — Get Day').first().json.dayLabel;
const list = Array.isArray(subscribers) ? subscribers : [];
const segments = { new_subscriber: [], returning: [] };
for (const sub of list) {
  if (!sub.email) continue;
  if (new Date(sub.subscribed_at) >= sevenDaysAgo) {
    segments.new_subscriber.push(sub);
  } else {
    segments.returning.push(sub);
  }
}
return [{ json: { segments, dayLabel, totalCount: list.length } }];

